# [doc = " Audit a set of `(file, contents)` sources for `wild` blocks (LR-9/S6). Deterministic (file-ordered)."] # [must_use] pub fn audit_wild (sources : & [(String , String)]) -> WildAudit { let mut audit = WildAudit :: default () ; let mut srcs : Vec < & (String , String) > = sources . iter () . collect () ; srcs . sort_by (| a , b | a . 0 . cmp (& b . 0)) ; for (file , src) in srcs { let lines : Vec < & str > = src . lines () . collect () ; for (i , raw) in lines . iter () . enumerate () { if ! opens_wild_block (raw) { continue ; } let justified = has_safety (& lines , i) ; let line = (i + 1) as u32 ; audit . inventory . push (WildBlock { file : file . clone () , line , justified , text : raw . trim () . to_owned () , }) ; if ! justified { audit . findings . push (Finding { family : "wild-audit" , rule : "wild-unjustified" , severity : Severity :: Medium , at : format ! ("{file}:{line}") , why : "a `wild` block (the denied-by-default unsafe escape hatch, LR-9/S6) has no \
                          adjacent `// SAFETY:` justification — every unsafe region must be justified \
                          (ADR-014); flagged, never silently trusted (G2)" . to_owned () , }) ; } } } audit }

# [doc = " Render the `wild`-audit `EXPLAIN` (no black box): the inventory + each unjustified finding's *why*."] # [must_use] pub fn explain_wild (audit : & WildAudit) -> String { let mut out = format ! ("wild-audit: {} block(s), {} justified, {} unjustified
" , audit . inventory . len () , audit . justified () , audit . unjustified ()) ; for b in & audit . inventory { let tag = if b . justified { "justified" } else { "UNJUSTIFIED" } ; out . push_str (& format ! ("  {}:{} [{tag}] {}
" , b . file , b . line , b . text)) ; } for f in & audit . findings { out . push_str (& format ! ("  finding [{}] {} at {}: {}
" , f . severity . as_str () , f . rule , f . at , f . why)) ; } out }
